import{bQ as a,aL as i,u as e,G as t}from"./chunks/framework.D06dwy5q.js";const r=JSON.parse('{"title":"02｜变量与引号","description":"","frontmatter":{},"headers":[],"relativePath":"02.Shell脚本/02-变量与引号.md","filePath":"02.Shell脚本/02-变量与引号.md","lastUpdated":null}'),n={name:"02.Shell脚本/02-变量与引号.md"};function h(p,s,l,d,k,o){return i(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="_02-变量与引号" tabindex="-1">02｜变量与引号 <a class="header-anchor" href="#_02-变量与引号" aria-label="Permalink to &quot;02｜变量与引号&quot;">​</a></h1><p>上一篇的脚本里用了 <code>$(whoami)</code> 把命令输出塞进字符串。但很多时候要存的不止这些——要存用户名、路径、要清理的目录、报警阈值。这些都要用变量。</p><p>变量看起来简单，但 Shell 里的变量和引号有个坑：同一行命令，加不加引号、用单引号还是双引号，结果可能完全不同。本篇讲变量赋值和引号规则，再讲一个让脚本更安全的开关 <code>set -euo pipefail</code>。</p><h2 id="一、变量赋值" tabindex="-1">一、变量赋值 <a class="header-anchor" href="#一、变量赋值" aria-label="Permalink to &quot;一、变量赋值&quot;">​</a></h2><p>变量赋值用等号，注意<strong>等号两边不能有空格</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;deploy&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">count</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">5</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">path</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/var/log/nginx&quot;</span></span></code></pre></div><p>这和 Python 等语言不一样。<code>user = &quot;deploy&quot;</code>（带空格）在 Shell 里会被当成一条命令：执行 <code>user</code> 这个命令，参数是 <code>=</code> 和 <code>&quot;deploy&quot;</code>。带空格的赋值是初学最常见的错误。</p><p>引用变量用 <code>$</code>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $user</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;清理目录: </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$path</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span></code></pre></div><p>更稳的写法是给变量名加花括号 <code>\${user}</code>，区分变量名边界：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;\${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">user</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}home&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 引用 user 变量，后面接 home</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$userhome</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # 引用 userhome 变量（多半没定义，得到空）</span></span></code></pre></div><h2 id="二、单引号和双引号的区别" tabindex="-1">二、单引号和双引号的区别 <a class="header-anchor" href="#二、单引号和双引号的区别" aria-label="Permalink to &quot;二、单引号和双引号的区别&quot;">​</a></h2><p>这是 Shell 里最容易踩的坑。看一个对比：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;world&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;hello </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # 双引号</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;hello $name&#39;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # 单引号</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>hello world</span></span>
<span class="line"><span>hello $name</span></span></code></pre></div><p>双引号里 <code>$name</code> 会展开成变量的值，单引号里 <code>$name</code> 原样输出。</p><p>规律：<strong>双引号允许变量展开和命令替换，单引号里一切都是字面值</strong>。</p><p>什么时候用哪个？要展开变量用双引号，要原样输出（正则、含特殊字符的字符串）用单引号。</p><h2 id="三、不加引号的陷阱" tabindex="-1">三、不加引号的陷阱 <a class="header-anchor" href="#三、不加引号的陷阱" aria-label="Permalink to &quot;三、不加引号的陷阱&quot;">​</a></h2><p>变量引用时不加引号也能跑，但有空格就出问题：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">path</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/var/log/nginx access&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $path        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 不加引号</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ls: cannot access &#39;/var/log/nginx&#39;: No such file or directory</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ls: cannot access &#39;access&#39;: No such file or directory</span></span></code></pre></div><p><code>$path</code> 不加引号时，Shell 把它按空格拆成两个词 <code>/var/log/nginx</code> 和 <code>access</code>，<code>ls</code> 收到两个参数。加了引号就是一个整体：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$path</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # 加双引号，当成一个路径</span></span></code></pre></div><p><strong>规律：引用变量时养成加双引号的习惯</strong>，尤其是路径、文件名这类可能含空格的值。不加引号一旦值里有空格或特殊字符，脚本行为就不可控。</p><h2 id="四、特殊变量" tabindex="-1">四、特殊变量 <a class="header-anchor" href="#四、特殊变量" aria-label="Permalink to &quot;四、特殊变量&quot;">​</a></h2><p>Shell 有一些预定义的特殊变量，常用这几个：</p><table tabindex="0"><thead><tr><th>变量</th><th>含义</th></tr></thead><tbody><tr><td><code>$?</code></td><td>上一条命令的退出码（0 成功，非 0 失败）</td></tr><tr><td><code>$0</code></td><td>脚本名</td></tr><tr><td><code>$1</code> <code>$2</code> ...</td><td>脚本的参数</td></tr><tr><td><code>$#</code></td><td>参数个数</td></tr><tr><td><code>$@</code></td><td>所有参数</td></tr><tr><td><code>$$</code></td><td>当前脚本的进程号</td></tr><tr><td><code>$!</code></td><td>最近一个后台进程的进程号</td></tr></tbody></table><p><code>$?</code> 最常用——判断上一条命令成功没：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp/backup</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$?</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -ne</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ]; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">then</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;创建目录失败&quot;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    exit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fi</span></span></code></pre></div><p>参数相关的（<code>$0</code>-<code>$@</code>）下一篇专门讲。</p><h2 id="五、set-euo-pipefail-让脚本更安全" tabindex="-1">五、set -euo pipefail：让脚本更安全 <a class="header-anchor" href="#五、set-euo-pipefail-让脚本更安全" aria-label="Permalink to &quot;五、set -euo pipefail：让脚本更安全&quot;">​</a></h2><p>看一段脚本：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#!/usr/bin/env bash</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /data/backup</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> *</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.tmp</span></span></code></pre></div><p>如果 <code>/data/backup</code> 不存在，<code>cd</code> 失败，但脚本不会停——继续执行 <code>rm -rf *.tmp</code>，在当前目录（可能是 <code>/root</code>）删掉所有 <code>.tmp</code> 文件。这就是脚本&quot;该停不停&quot;的事故源。</p><p><code>set -euo pipefail</code> 是脚本的安全开关，放在 shebang 后面：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#!/usr/bin/env bash</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -euo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pipefail</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /data/backup</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> *</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.tmp</span></span></code></pre></div><p>三个选项各管一件事：</p><table tabindex="0"><thead><tr><th>选项</th><th>作用</th><th>不加的后果</th></tr></thead><tbody><tr><td><code>-e</code></td><td>命令失败立即退出</td><td>脚本继续往下跑，可能在错误状态下执行后续命令</td></tr><tr><td><code>-u</code></td><td>引用未定义变量报错</td><td>未定义变量得到空串，悄悄出错难排查</td></tr><tr><td><code>-o pipefail</code></td><td>管道中任一命令失败则整个失败</td><td>只看最后一个命令的退出码，前面的失败被吞</td></tr></tbody></table><p>逐个看：</p><p><strong><code>-e</code></strong>：<code>cd</code> 失败就退出，不会继续跑 <code>rm</code>。避免&quot;在错误状态下继续执行&quot;。</p><p><strong><code>-u</code></strong>：变量名拼错（<code>$usr</code> 写成 <code>$user</code> 的反例）时直接报错退出，而不是得到空值悄悄继续。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$usr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # usr 未定义，报错退出：usr: unbound variable</span></span></code></pre></div><p><strong><code>-o pipefail</code></strong>：默认管道只看最后一个命令的退出码。<code>grep error /var/log/messages | head</code> 里 <code>grep</code> 没找到返回非 0，但 <code>head</code> 成功返回 0，整条管道看起来成功。<code>pipefail</code> 让管道任一段失败都算失败。</p><p>生产脚本的标准开头就是这个组合：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#!/usr/bin/env bash</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -euo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pipefail</span></span></code></pre></div><p>不是所有脚本都该加 <code>-e</code>——有些命令失败是预期的（比如 <code>grep</code> 没匹配到返回 1），加了 <code>-e</code> 会让脚本退出。这种情况用 <code>|| true</code> 显式说明&quot;失败也继续&quot;：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;error&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/log/messages</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ||</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span></span></code></pre></div><h2 id="六、变量的作用域" tabindex="-1">六、变量的作用域 <a class="header-anchor" href="#六、变量的作用域" aria-label="Permalink to &quot;六、变量的作用域&quot;">​</a></h2><p>默认 Shell 变量是当前 shell 的局部变量。脚本里定义的变量，脚本结束就没了。但如果脚本里调用另一个脚本，变量默认传不过去：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># a.sh</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;deploy&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> b.sh</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # b.sh 里看不到 name</span></span></code></pre></div><p>要让变量被子进程看到，用 <code>export</code>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># a.sh</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;deploy&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> b.sh</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # b.sh 里能读到 name</span></span></code></pre></div><p>函数里的局部变量用 <code>local</code>，避免污染外层。这个在函数篇讲。</p><h2 id="学会了之后" tabindex="-1">学会了之后 <a class="header-anchor" href="#学会了之后" aria-label="Permalink to &quot;学会了之后&quot;">​</a></h2><p>变量和引号是 Shell 脚本的基础——存值、引用值、控制变量展开。<code>set -euo pipefail</code> 让脚本在出错时停下，是生产脚本的安全底线。</p><p>下一篇讲命令替换和退出码——怎么把命令的输出存进变量、怎么用退出码做逻辑判断。</p>`,56)])])}const g=a(n,[["render",h]]);export{r as __pageData,g as default};
